head.script:
/**
 * @event 
 * @name onpageload 
 * @description 화면 초기화
 */
scwin.onpageload = function () { };



/**
 * @event 
 * @name onUdcCompleted 
 * @description UDC 완료
 */
scwin.onUdcCompleted = function () {

    const gauceUtillOption = [
        {
            method: "getGridCombo",
            param1: "SD136",
            param2: false,
            compID: "gr_carryInOutInfo:crryinEdiFlag1"
        }
    ];
    $c.data.setGauceUtil(gauceUtillOption, () => {
        let columnIndex = gr_carryInOutInfo.getColumnIndex('crryinEdiFlag1');
        let targetDlt = $p.getComponentById(gr_carryInOutInfo.getColumnDataListInfo(columnIndex).id);

        targetDlt.setRowJSON(0, { code: '99', name: '미등록' }, false);
    });

};



/**
 * @event 
 * @name ondataload 
 * @description 코드 완료
 */
scwin.ondataload = function () {
    scwin.globalVars();
    scwin.f_OnLoad();
}



/**
 * @method 
 * @name globalVars 
 * @description 전역변수선언
 */
scwin.globalVars = function () {

    scwin.selfTransClntNo = "";
    scwin.selfTransClntNm = "";
    scwin.impExpClsCd = "";
    scwin.onReqNo = "";

    //세션정보
    const loginDTO = $c.data.getMemInfo();
    scwin.loginId = loginDTO.userId;

    scwin.userClsCd = loginDTO.userClsCd ?? '';
    //사용자구분코드(01:그룹사구분코드(01:그룹사, 02:협력업체(운송), 03:선사, 04:화주, 05:자가운송업체, 06:렌터카(고객), 07:정비(고객))

    scwin.clntNo = loginDTO.clntNo;  //거래처번호
    scwin.clntNm = loginDTO.clntNm;  //거래처명

    scwin.strCurDate = $c.date.getServerDateTime('yyyyMMdd');

    scwin.selfTransClntNo = $c.data.getParameter("selfTransClntNo") ?? scwin.clntNo; // 자가운송사명
    scwin.selfTransClntNm = $c.data.getParameter("selfTransClntNm") ?? scwin.clntNm; // 자가운송사명

    scwin.impExpClsCd = $c.data.getParameter("impExpClsCd") ?? '';	// 자가운송사명
    scwin.onReqNo = $c.data.getParameter("onReqDt") ?? '';          // 요청번호

    scwin.MSG_OP_ERR_001 = "시간형식이 맞지 않습니다.";
    scwin.MSG_OP_ERR_005 = "%1은(는) %2보다 커야합니다.";
    scwin.currDate = "";
    scwin.currTime = "";
    scwin.tempHoliday = "";

};



/**
 * @method 
 * @name f_OnLoad 
 * @description 화면로딩시
 */
scwin.f_OnLoad = function () {

    // todo - asis edit관련 속성 없으나 동작이 달라 추가
    gr_onReqAdmitInfo.setGridReadOnly(true);

    impExpClsNm.setValue('');
    onReqNo.setValue('');
    blBookingNo.setValue('');
    admitClsNm.setValue('');
    odrNo.setValue('');
    lineNm.setValue('');
    realMchtClntNm.setValue('');
    demDt.setValue('');
    selfTransClntNm.setValue('');

    scwin.f_getTime();

    if (scwin.userClsCd != "01") {  //사용자 구분 : 05
        ed_srchSelfTransCoCd.setValue(scwin.clntNo);
        txt_srchSelfTransCoNm.setValue(scwin.clntNm);
        ed_srchOnReqNo.setValue(scwin.onReqNo);
        $c.gus.cfDisableObjects([ed_srchSelfTransCoCd, txt_srchSelfTransCoNm, img_srchSelfTransCoCd]);

        scwin.f_RetrieveCrryoutInfo("TOBE");
    } else {
        ed_srchSelfTransCoCd.setValue("");
        txt_srchSelfTransCoNm.setValue("");
        $c.gus.cfEnableObjects([ed_srchSelfTransCoCd, txt_srchSelfTransCoNm, img_srchSelfTransCoCd]);
    };

    $c.gus.cfEnableObjects([btn_carryingInOutEDI, btn_save]);

    // 테스트데이터
    // ed_srchSelfTransCoCd.setValue('227723');
    // ed_srchOnReqNo.setValue('201611280063');

    // ed_srchSelfTransCoCd.setValue('102823');
    // ed_srchOnReqNo.setValue('202603050021');

    // ed_srchSelfTransCoCd.setValue('125619');
    // ed_srchOnReqNo.setValue('200608170220');

};



/**
 * @method 
 * @name f_OpenPopup 
 * @description 코드 조회 팝업
 */
scwin.f_OpenPopup = function (id, obj, param1, param2, pWinCloseTF, pWhere) {

    pWhere = ",LOGISCLNT2";
    udc_srchSelfTransCoCd.setSelectId(id);

    udc_srchSelfTransCoCd.cfCommonPopUp(
        (rtnList) => {

            if (rtnList != null && rtnList[0] != "N/A") {
                for (let i = 0; i < obj.length; i++) {
                    let comp = $p.getComponentById(obj[i]);
                    comp.setValue(rtnList[i % 2]);
                };
            } else {
                for (let i = 0; i < obj.length; i++) {
                    let comp = $p.getComponentById(obj[i]);
                    comp.setValue('');
                };
            };

        },
        param1, param2, pWinCloseTF,
        null, null, null, null,
        pWhere,
        null, null, null, null
    );

};



/**
 * @method 
 * @name f_RetrieveCrryoutInfo 
 * @description 조회
 */
scwin.f_RetrieveCrryoutInfo = async function (toBe) {

    if (toBe == "" && !$c.gus.cfValidate([tb_srchCond])) {
        return;
    };

    let retObj = await $c.sbm.execute(sbm_retreiveCrryoutIntendInfo);
    if (retObj.responseJSON.resultDataSet[0].Msg == 'SUCC') {
        await scwin.sbm_retreiveCrryoutIntendInfo_submitdone(retObj);
    };

};



/**
 * @method 
 * @name f_Save 
 * @description 생성
 */
scwin.f_Save = function () {

    if (!scwin.f_prefareCheck()) return;

    if (!ds_carryInOutInfo.getModifiedIndex().length > 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["예정정보"]); //변경된 정보가 없습니다.
        return;
    };

    //라인코드가 SITC이고, ODR_CTRL_CLS_CD = 3 인경우에 체선일자 체크
    let firstRowData = ds_carryInOutInfo.getRowJSON(0);
    if (firstRowData.lineCd == "SITC" && firstRowData.odrCtrlClsCd == "3") {

        let totalRow = ds_carryInOutInfo.getTotalRow();
        let rowData = null, demDate = '';

        if (totalRow > 0) {
            for (let i = 0; i < totalRow; i++) {

                rowData = ds_carryInOutInfo.getRowJSON(i);
                demDate = rowData.cntrCrryoutCloseDt;

                if (demDate == "") {
                    $c.win.alert("반출기한을 지정받으세요.");
                    return;
                };

            };
        };

    };



    let focusedIdx = ds_onReqInfo.getRowPosition() ?? 0;
    let focusedData = ds_onReqInfo.getRowJSON(focusedIdx);

    let strOdrNo = focusedData.odrNo;


    if (strOdrNo.slice(1, 3) == "C2") {
        switch (focusedData.lineCd) {
            case "TSL":
                $c.win.alert("TSL라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
                return false;

            case "EAS":
                $c.win.alert("EAS라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
                return false;

            case "GBH":
                $c.win.alert("GBH라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
                return false;

            case "KYW":
                $c.win.alert("KYW라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
                return false;

            case "COH":
                if (scwin.loginId == "010028" || scwin.loginId == "021245") {
                    $c.win.confirm(
                        "저장 하시겠습니까?",
                        scwin.confirmCallback,
                        { callBackParam: { callFnc: 'f_Save', lineNm: 'COH' } }
                    );
                };
                return false;

            case "YNK":
                if (scwin.loginId == "010028" || scwin.loginId == "021245") {
                    $c.win.confirm(
                        "저장 하시겠습니까?",
                        scwin.confirmCallback,
                        { callBackParam: { callFnc: 'f_Save', lineNm: 'YNK' } }
                    );
                };
                return false;

            case "SWIL":
                let topFocusIdx = ds_carryInOutInfo.getRowPosition();
                if (ds_carryInOutInfo.getCellData(topFocusIdx, "wrkPlCd") == "6C09") {
                    $c.win.confirm(
                        "저장 하시겠습니까?",
                        scwin.confirmCallback,
                        { callBackParam: { callFnc: 'f_Save', lineNm: 'SWL' } }
                    );
                };
                return false;

            default:
                break;
        };
    };



    switch (focusedData.lineCd) {
        case "APL":
            $c.win.alert("APL라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
            return false;

        case "SITC":
            if (["072893", "073294", "030600", "010028", "021245"].includes(scwin.loginId)) {
                $c.win.confirm(
                    "저장 하시겠습니까?",
                    scwin.confirmCallback,
                    { callBackParam: { callFnc: 'f_Save', lineNm: "SITC" } }
                );
            };
            return false;

        case "NOLS": case "TCLC": case "SOFC": case "TMSC": case "TJM":
        case "MAS": case "JJS": case "DWH": case "RHT": case "ONE":
            if (scwin.loginId == "040300") {
                $c.win.confirm(
                    "저장 하시겠습니까?",
                    scwin.confirmCallback,
                    {
                        callBackParam: {
                            callFnc: 'f_Save',
                            lineNm: "NOLS, TCLC, SOFC, TMSC, TJM, MAS, JJS, DWH, RHT, ONE "
                        }
                    }
                );
            };
            return false;

        case "COS":
            $c.win.alert("COS 라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
            return false;

        case "MOL":
            $c.win.alert("MOL 라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
            return false;

        default:
            $c.win.confirm(
                "저장 하시겠습니까?",
                scwin.confirmCallback,
                { callBackParam: { callFnc: 'f_Save' } }
            );
            break;
    };

};



/**
 * @method 
 * @name confirmCallback 
 * @description
 */
scwin.confirmCallback = async function (e) {

    if (e.callFnc == 'f_Save') {
        if (!e.clickValue) {
            $c.win.alert(e.lineNm + "라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
            return;
        };

        let retObj = await $c.sbm.execute(sbm_createCrryoutIntendInfo);
        if (retObj.responseJSON.resultDataSet[0].Msg == 'SUCC') {
            await scwin.sbm_createCrryoutIntendInfo_submitdone(retObj);
        };
    };

};



/**
 * @method 
 * @name f_prefareCheck 
 * @description 행추가전 디폴트값 Check
 */
scwin.f_prefareCheck = function () {

    let firstRowData = ds_onReqInfo.getRowJSON(0);
    if (firstRowData.impExpClsCd == "I" 	//수입인경우
        && firstRowData.demDt != "" 		//체선일자가 null이 아닌 경우
        && demDt.getValue() < scwin.strCurDate) {	//체선일자는 반출예정일자보다 커야 한다.
        $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_005, ["체선일자", "반출예정일"]);
        return false;
    };


    let totalRow = ds_carryInOutInfo.getTotalRow();
    for (i = 0; i < totalRow; i++) {

        let rowData = ds_carryInOutInfo.getRowJSON(i);

        if (ds_carryInOutInfo.getRowStatus(i) == "3") {

            if (rowData.crryinoutIntendDt == "") {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["상차예정일"]);
                return false;
            };

            if (rowData.crryinoutIntendHh == "") {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["시간"]);
                return false;
            };

            if (!dscommon.cf_gidHourCheck(rowData.crryinoutIntendHh) ||
                rowData.crryinoutIntendHh.length < 4) {
                $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_001);
                return false;
            };

            if (rowData.vehclNo == "") {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["차량번호"]);
                return false;
            };

            if (rowData.vehclIdCardNo == "") {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["차량번호"]);
                return false;
            };

            if (rowData.drvNm == "") {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["기사명"]);
                return false;
            };

            if (rowData.drvTelNo == "") {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["연락처"]);
                return false;
            };
        };
    };

    return true;

};



/**
 * @method 
 * @name f_openCommPopUpGrid 
 * @description 상차지 조회 Popup 처리 : 그리드에서 입력된 코드정보로 상차지를 조회
 */
scwin.f_openCommPopUpGrid = function (row, pClose) {

    // 선언부
    let pCode = "", pName = "";

    // 품명 코드팝업			
    pName = ds_carryInOutInfo.getCellData(row, "wrkPlNm");		// 상차지명

    udc_gridComCode.setSelectId('retrieveWrkPlInfo');

    udc_gridComCode.cfCommonPopUp(
        (rtnList) => {
            $c.gus.cfSetGridReturnValue(rtnList, ds_carryInOutInfo, row, "wrkPlCd", "wrkPlNm");
        },
        pCode,
        pName,
        pClose,
        null,
        null,
        null,
        null,
        null,
        null,
        null,
        null,
        null,
        null,
        null,
        "상차지,상차지코드,상차지명"
    );

    return false;

};



/**
 * @method 
 * @name f_SetInitCondVal 
 * @description 조회조건 초기화
 */
scwin.f_SetInitCondVal = function () {
    $c.gus.cfInitObjects(tb_srchCond);
};



/**
 * @method 
 * @name f_openCommonPopUp 
 * @description 조회 팝업
 */
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {

    // 선언부
    let param = "";
    let focusRowIdx = ds_carryInOutInfo.getRowPosition();
    let rowData = ds_carryInOutInfo.getRowJSON(focusRowIdx);

    switch (disGubun) {
        case 1:
            // 차량번호 Popup
            pCode = rowData.vehclIdCardNo;
            pName = "";
            udc_gridComCode.setSelectId('retrieveShotVehcl');

            rtnList = udc_gridComCode.cfCommonPopUp((rtnList) => {
                if (rtnList != null) {
                    //return value Assign
                    ds_carryInOutInfo.setCellData(focusRowIdx, "vehclIdCardNo", rtnList[1]);	//자가운송사코드
                } else {
                    ds_carryInOutInfo.setCellData(focusRowIdx, "vehclIdCardNo", ""); 	//자가운송사코드
                }
            },
                pCode, pName, "T", null, null,
                null, null, param, null, null,
                null, null, null, pAllSearch,
                "차량번호,차랑단축번호,차량번호"
            );


            break;

        case 2:
            //상차요청번호 Pop up
            let rtnList = await $c.win.openPopup(
                '/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_04p2.xml',
                { type: 'browserPopup', width: '500px', height: '393px' },
                { param: 'I' + ';' + ed_srchSelfTransCoCd.getValue() }
            );

            if (rtnList != null) {
                ed_srchOnReqNo.setValue(rtnList[0]);	//상차요청번호
            } else {
                ed_srchOnReqNo.setValue("");	//상차요청번호
            }
            break;

        default:
            break;
    };

};



/**
 * @method 
 * @name f_ResultsExcel 
 * @description 엑셀파일로 저장
 */
scwin.f_ResultsExcel = function () {

    //sheet명, 저장파일명,     저장 다이얼로그
    let excelName = '반출(상차)예정정보등록(포털)';

    let options = {
        sheetName: excelName,
        fileName: excelName + ".xlsx"
    };

    $c.data.downloadGridViewExcel(gr_onReqAdmitInfo, options);

};



/**
 * @method 
 * @name f_crryInOutEDI 
 * @description 반출입예정정보EDI등록
 */
scwin.f_crryInOutEDI = async function (bAlertFlag, bSaveFlag, bTransferFlag, row, bDeleteFlag) {

    if (ds_carryInOutInfo.getTotalRow() == 0) return;

    if (ds_carryInOutInfo.getCellData(row, "vehclNo") == "") {
        if (bAlertFlag) {
            $c.gus.cfAlertMsg("운송차량이 없습니다");
        };
        return false;
    };


    //저장,전송인경우
    if (bSaveFlag) {

        dma_searchEDI.setEmptyValue();

        let jsonData = {
            "qryClsCd": "1",
            "transWrkIndictNo": ds_retrievePreliminaryInformationEdi.getCellData(row, "scwin.onReqNo"),
            "odrNo": ds_results.getCellData(row, "odrNo"),
            "cntrSeq": ds_results.getCellData(row, "cntrSeq"),
            "wrkPathSeq": ds_results.getCellData(row, "odrWrkPathSeq"),
            "wrkStpSeq": ds_results.getCellData(row, "odrWrkStpSeq"),
            "vehclNo": ds_results.getCellData(row, "vehclNo"),
            "crryinoutDt": ds_results.getCellData(row, "wrkStDt"),
            "crryinDt": ds_results.getCellData(row, "wrkEndDt"),
            "odrNo": ds_results.getCellData(row, "odrNo"),
            "cntrNo": ds_results.getCellData(row, "cntrNo"),
            "dptWrkPlCd": ds_results.getCellData(row, "dptWrkPlCd"),
            "arvWrkPlCd": ds_results.getCellData(row, "arvWrkPlCd"),
            "sndFlag": (bTransferFlag == true ? "1" : "0"),
            "delFlag": (bDeleteFlag == true ? "1" : "0"),
        };

        dma_searchEDI.setJSON(jsonData);

        //메시지 표시를 위해 저장(작업완료후 전송, 저장여부를 메시지로 표시해줌)
        gv_bEdiTransfer = bTransferFlag;
        $c.sbm.execute(sbm_saveEDI);
        return true;

    };


    let ediFocusedIdx = ds_retrievePreliminaryInformationEdi.getRowPosition();
    let ediRowData = ds_retrievePreliminaryInformationEdi.getRowJSON(ediFocusedIdx);
    let infoFocusedIdx = ds_carryInOutInfo.getRowPosition();
    let infoRowData = ds_carryInOutInfo.getRowJSON(infoFocusedIdx);
    let arrParam = new Array();


    arrParam[0] = new Array(
        "1",	//조회구분 ("" : 운송작업지시, "1" : 반출입)
        ediRowData.onReqNo,
        ediRowData.odrNo,
        ediRowData.cntrSeq,
        ediRowData.odrWrkPathSeq,
        ediRowData.odrWrkStpSeq,
        infoRowData.vehclNo,
        infoRowData.vehclNo,
        infoRowData.vehclIdCardNo,
        infoRowData.crryinoutIntendDt,
        infoRowData.crryinoutIntendDt,
        infoRowData.cntrNo,
        infoRowData.wrkPlCd,
        "",
        infoRowData.wrkPlNm,
        "",
        "CO",
        "N"
    );

    arrParam[1] = new Array(
        infoRowData.onReqNo,
        infoRowData.vehclNo,
        infoRowData.vehclIdCardNo,
        infoRowData.drvNm,
        infoRowData.drvTelNo,
        infoRowData.crryinoutIntendDt,
        infoRowData.crryinoutIntendHh,
        "",
        ""
    );

    await $c.win.openPopup(
        '/ui/ds/op/wrkplan/transwrkplan/op_202_02_21p.xml',
        {
            popupName: '반출입예정정보EDI등록',
            width: '1100px',
            height: '1080px',
        },
        {
            arrParam: arrParam,
            'crryoutEdiType': 'CO',
            'crryinEdiType': 'N'
        }
    );

    scwin.f_RetrieveCrryoutInfo();
    return true;

}; 



/**
 * @method 
 * @name f_retrievePreliminaryInformationEdi 
 * @description 
 */
scwin.f_retrievePreliminaryInformationEdi = async function () {

    if (!ds_onReqInfo.getTotalRow() > 0) return;

    //현재시간 세팅
    scwin.f_getTime();

    let carryInOutFocusedIdx = ds_carryInOutInfo.getRowPosition();
    let carryInOutRowData = ds_carryInOutInfo.getRowJSON(carryInOutFocusedIdx);
    if (scwin.currTime > "1730" && carryInOutRowData.wrkPlCd == "6C01") {
        $c.win.alert("17시 30분 이후에는 " + carryInOutRowData.wrkPlNm + "의 요청으로 EDI 전송을 할 수 없습니다.");
        return false;
    }

    let focusedIdx = ds_onReqInfo.getRowPosition() ?? 0;
    let rowData = ds_onReqInfo.getRowJSON(focusedIdx);
    let strOdrNo = rowData.odrNo;

    // PRISM OPEN에 의한 SITC, NOLS, SOFC, TCLC라인 코피노전송 막기 (SITC는 수출만 막기), 2014.09.22 TMSC라인 추가
    if (strOdrNo.slice(1, 3) == "C4" && rowData.lineCd == "SITC") {
        $c.win.alert("SITC라인은 PRISM선사이므로 eTRANS에서 전송하세요 .");
        return false;
    };

    let prismArray = ["NOLS", "SOFC", "TCLC", "TMSC", "TJM", "MAS", "JJS", "DWH", "RHT", "ONE"];
    if (prismArray.includes(rowData.lineCd)) {
        $c.win.alert("NOLS, SOFC, TCLC, TMSC, TJM, MAS, JJS, DWH, RHT, ONE 라인은 PRISM선사이므로 eTRANS에서 전송하세요 .");
        return false;
    };

    // PRISM OPEN에 의한 SITC, NOLS, SOFC, TCLC라인 코피노전송 막기
    if (strOdrNo.slice(1, 3) == "C2") {
        switch (rowData.lineCd) {
            case "TSL": case "EAS": case "PAN": case "SITC":
            case "GBH": case "KYW": case "COHAPL": case "YNK":
            case "COS": case "MOL": case "SWIL":
                let lineNm = rowData.lineCd
                if (rowData.lineCd == 'PAN') lineNm = 'PANSTAR';
                $c.win.alert(lineNm + "라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
                return false;

            default:
                break;
        };
    };

    if (["APL", "SKR"].includes(rowData.lineCd)) {
        $c.win.alert(rowData.lineCd + "라인 반출입처리는 KLNET통하여  처리하세요!!!");
        return false;
    };

    if (carryInOutRowData.crryinEdiFlag1 == '' && carryInOutRowData.crryinCyFlag == '') {
        $c.win.alert("반출입 예정 정보 등록을 하신후 반출입예정정보(COPINO EDI)등록을 하세요");
        return;
    };

    if (carryInOutRowData.crryinoutPrgsStsNm == '대기') {
        $c.win.alert("반출입 예정 정보 등록을 하신후 반출입예정정보(COPINO EDI)등록을 하세요");
        return;
    };

    //KBCTCY에서 수출자가운송 반출예정정보 등록시 COPINO EDI 전송못하도록 함
    //김성지 대리 요청
    if (carryInOutRowData.wrkPlCd == "6C01" &&
        (strOdrNo.slice(1, 3) == "C4" || strOdrNo.slice(1, 3) == "C6")) {
        $c.win.alert(
            "상차지가 " + carryInOutRowData.wrkPlNm +
            "인 경우 담당자가  COPINO EDI를 전송합니다."
        );
        return;
    };

    let strOdrNos = rowData.odrNo;
    if (strOdrNos.slice(1, 3) == "C2") {   //C2오더일때
        // 현위치와 하선지가 다른경우
        if (carryInOutRowData.currPosCd != carryInOutRowData.arvWrkPlCd) {
            $c.win.alert(
                "직반출 건이 아닙니다. 담당자에게 확인하세요." +
                "[" + carryInOutRowData.currPosCd + ":" + carryInOutRowData.arvWrkPlCd + "]"
            );
            return;
        };
    };

    jsonData = {
        "selfTransClntNo": carryInOutRowData.selfTransClntNo,
        "onReqNo": carryInOutRowData.onReqNo,
        "cntrNo": carryInOutRowData.cntrNo,
        "impExpClsCd": carryInOutRowData.impExpClsCd,
        "cntrDsgYn": carryInOutRowData.cntrDsgYn,
        "wrkPlCd": carryInOutRowData.wrkPlCd,
        "gubun": carryInOutRowData.gubun,
        "cntrSeq": carryInOutRowData.cntrSeq,
    };

    dma_condition.setJSON(jsonData);

    let retObj = await $c.sbm.execute(sbm_retrievePreliminaryInformationEdi);
    if (retObj.responseJSON.resultDataSet[0].Msg == 'SUCC') {
        await scwin.sbm_retrievePreliminaryInformationEdi_submitdone(retObj);
    };

};



/**
 * @method 
 * @name f_OzReport 
 * @description 발행 
 */
scwin.f_OzReport = async function () {

    if (scwin.strCurDate < "20110822") {
        $c.win.alert("상차증발행은 2011년 8월 22일부터 사용할 수 있습니다.");
        return false;
    };


    // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
    let check = 0;
    let crryinoutIntendNo = "";
    let printYn = 0;
    let rowCnt = ds_carryInOutInfo.getTotalRow();
    let rowData = null;

    for (let i = 0; i < rowCnt; i++) {

        rowData = ds_carryInOutInfo.getRowJSON(i);

        if (rowData.chk == 1) {
            //검색어 세팅
            dma_printYnCondition.set("selfTransClntNo", rowData.selfTransClntNo);
            dma_printYnCondition.set("onReqNo", rowData.scwin.onReqNo);
            dma_printYnCondition.set("onReqGoodsSeq", rowData.onReqGoodsSeq);
            dma_printYnCondition.set("printYn", 1);
            crryinoutIntendNo = rowData.crryinoutIntendNo;
            printYn = rowData.printYn;
        } else {
            check++;
        };

    };


    if (rowCnt == check) {
        $c.win.alert("상차증을 발행할 컨테이너를 선택하세요.");
        return false;
    };

    if (crryinoutIntendNo == "") {
        $c.win.alert("선택된 컨테이너는 예정정보를 먼저 등록하신 후에 상차증을 발행할 수 있습니다.");
        return false;
    };

    if (printYn >= 1) {
        $c.win.alert("선택된 컨테이너는 이미 상차증이 발행되었습니다.\n추가 발행을 원하시면 담당자에게 문의하세요.");
        return false;
    };



    //update
    $c.sbm.execute(sbm_updatePrintYn);

    let ozrId = "/ds/op/wrkrslts/cywrkrslts/op_301_02_21r.ozr";
    let odiId = "op_301_02_21r"

    // OZ리포트
    const data = {
        reportName: ozrId,
        // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
        odiParam: {
            'sysPath': 'dbl.ds.op.wrkrslts.cywrkrslts',
            'crryinoutIntendNo': crryinoutIntendNo
        },

        // OZ 뷰어에 대한 설정(상세 설정은 'oz report viewer guide.pdf'를 참조)
        viewerParam: {
            'useprogressbar': 'false'
        },

        // 리포트(OZR)에 적용할 파라미터를 설정(OZFormParam)
        formParam: {},
    }


    let options = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };

    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", options, data);

    scwin.f_RetrieveCrryoutInfo();

};



/**
