/**
 * @event 
 * @name sbm_retreiveCrryoutIntendInfo_submitdone 
 * @description 조회 TR 정상
 */
scwin.sbm_retreiveCrryoutIntendInfo_submitdone = async function (e) {

    if (e.responseJSON.resultDataSet[0].Code == -1) return;

    // 총 건수 초기화
    totalRow1.setValue(0);
    totalRow2.setValue(0);

    let rowCnt = ds_onReqInfo.getRowCount();

    if (rowCnt == 0) {
        ds_onReqAdmitInfo.removeAll();
        ds_carryInOutInfo.removeAll();
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    };

    totalRow1.setValue(ds_onReqAdmitInfo.getTotalRow());
    totalRow2.setValue(ds_carryInOutInfo.getTotalRow());

    let focusedIdx = ds_onReqInfo.getRowPosition() ?? 0;
    let rowData = ds_onReqInfo.getRowJSON(focusedIdx);
    if (rowData.lineCd == "TSL" && rowData.odrNo.slice(1, 3) == "C2") {
        $c.gus.cfDisableObjects([btn_save]);
    };


    // 상차요청 정보 
    if (rowCnt == 0) {
        printYn.hide();
        gr_carryInOutInfo.setColumnVisible('chk', false);
        return;
    };


    let firstRowData = ds_onReqInfo.getRowJSON(0);
    // for=ds_onReqInfo event=OnLoadCompleted(rowCnt)
    if (firstRowData.impExpClsCd == "I") {
        impExpClsNm.setValue(firstRowData.impExpClsNm);
        onReqNo.setValue(firstRowData.onReqNo);
        blBookingNo.setValue(firstRowData.blNo);
        admitClsNm.setValue(firstRowData.admitClsNm);
        odrNo.setValue(firstRowData.odrNo);
        lineNm.setValue(firstRowData.lineNm);
        realMchtClntNm.setValue(firstRowData.realMchtClntNm);
        demDt.setValue(firstRowData.demDt);
        selfTransClntNm.setValue(firstRowData.selfTransClntNm);

        gr_carryInOutInfo.setColumnReadOnly("nrm", false);
        gr_carryInOutInfo.setColumnReadOnly("wrkPlNm", false);
        gr_carryInOutInfo.setColumnReadOnly("crryinoutIntendHh", '');
        gr_carryInOutInfo.setColumnReadOnly("vehclNo", '');
        gr_carryInOutInfo.setColumnReadOnly("vehclIdCardNo", '');
        gr_carryInOutInfo.setColumnReadOnly("drvNm", '');
        gr_carryInOutInfo.setColumnReadOnly("drvTelNo", '');

        gr_carryInOutInfo.setHeaderColor("nrmHeader", '');
        gr_carryInOutInfo.setHeaderColor("wrkPlNmHeader", '');
        gr_carryInOutInfo.setHeaderColor("crryinoutIntendDtHeader", '');

    } else if (firstRowData.impExpClsCd == "O") {

        impExpClsNm.setValue(firstRowData.impExpClsNm);
        onReqNo.setValue(firstRowData.onReqNo);
        blBookingNo.setValue(firstRowData.bookingNo);
        admitClsNm.setValue(firstRowData.admitClsNm);
        odrNo.setValue(firstRowData.odrNo);
        lineNm.setValue(firstRowData.lineNm);
        realMchtClntNm.setValue(firstRowData.realMchtClntNm);
        demDt.setValue(firstRowData.demDt);
        selfTransClntNm.setValue(firstRowData.selfTransClntNm);

        let nrmHeaderClass = gr_carryInOutInfo.getHeaderClass('nrmHeader');
        gr_carryInOutInfo.removeHeaderClass('nrmHeader', nrmHeaderClass);
        let wrkPlNmHeaderClass = gr_carryInOutInfo.getHeaderClass('wrkPlNmHeader');
        gr_carryInOutInfo.removeHeaderClass('nrmHeader', wrkPlNmHeaderClass);

        if ($c.num.parseInt(firstRowData.cntrDsgYn) == 1) { // 컨테이너
            gr_carryInOutInfo.setColumnReadOnly("nrm", true);
            gr_carryInOutInfo.setColumnReadOnly("wrkPlNm", true);

            gr_carryInOutInfo.removeHeaderClass('nrmHeader', 'txt-blue');
            gr_carryInOutInfo.removeHeaderClass('wrkPlNmHeader', 'txt-blue');

        } else if ($c.num.parseInt(firstRowData.cntrDsgYn) == 0) { // 규격
            gr_carryInOutInfo.setColumnReadOnly("nrm", '');
            gr_carryInOutInfo.setColumnReadOnly("wrkPlNm", true);

            gr_carryInOutInfo.setHeaderClass('nrmHeader', 'txt-blue');
            gr_carryInOutInfo.setHeaderClass('wrkPlNmHeader', 'txt-blue');
        }

        gr_carryInOutInfo.setColumnReadOnly("crryinoutIntendDt", '');
        gr_carryInOutInfo.setColumnReadOnly("crryinoutIntendHh", '');
        gr_carryInOutInfo.setColumnReadOnly("vehclNo", '');
        gr_carryInOutInfo.setColumnReadOnly("vehclIdCardNo", '');
        gr_carryInOutInfo.setColumnReadOnly("drvNm", '');
        gr_carryInOutInfo.setColumnReadOnly("drvTelNo", '');

        gr_carryInOutInfo.setHeaderClass('crryinoutIntendDtHeader', 'txt-red');
    };


    txt_odrRmk.setValue(firstRowData.rmk);

    if (demDt.getValue().length == 8)
        demDt.setValue($c.gus.cfGetFormatStr(demDt.getValue(), "####/##/##"));

    if (firstRowData.admitClsCd != "O") {
        $c.win.alert("승인 후 진행 하세요." + firstRowData.admitClsCd);
        return;
    };



    if (rowCnt == 0) {
        printYn.hide();
        gr_carryInOutInfo.setColumnVisible("chk", false);
        return;
    };


    focusedIdx = ds_carryInOutInfo.getRowPosition();
    rowData = ds_carryInOutInfo.getRowJSON(focusedIdx);

    if (rowData.crryinEdiFlag1 == '') {
        $c.gus.cfDisableObjects([btn_carryingInOutEDI]);
    } else {
        $c.gus.cfEnableObjects([btn_carryingInOutEDI]);
    };


    if (rowData.crryinCyFlag == 'C') {
        let strOdrNo = rowData.odrNo;
        if (strOdrNo.slice(1, 3) == "C2") {
            if (["TSL", "EAS", "TSL"].includes(rowData.lineCd)) {
                $c.gus.cfDisableObjects([btn_save]);
            };
        } else {
            $c.gus.cfEnableObjects([btn_save]);
        };
    };

    if (rowData.crryinEdiFlag1 == '' && rowData.crryinCyFlag == '') {
        $c.gus.cfEnableObjects([btn_carryingInOutEDI]);
    };


    await scwin.f_getTime();

    if (!["mig101", "snowmoon", "dunky"].includes(scwin.loginId)) {
        if (scwin.currTime > "1700" && rowData.wrkPlCd == "6C01") {
            btn_carryingInOutEDI.setValue("17:00 이후 " + rowData.wrkPlNm + "는 Copino EDI전송불가");
            $c.gus.cfDisableObjects([btn_carryingInOutEDI]);
        };
    };


    //수출 경인지역인 경우에만 상차증 발행버튼 보여줌
    if (rowData.wrkPlCd == "4C02" && ds_onReqInfo.getCellData(0, "impExpClsCd") == "O") {
        printYn.show('');
        gr_carryInOutInfo.setColumnVisible("chk", true);
    } else {
        printYn.hide();
        gr_carryInOutInfo.setColumnVisible("chk", false);
    };

    ds_onReqInfo.setRowPosition(0);
    ds_onReqAdmitInfo.setRowPosition(0);
    ds_carryInOutInfo.setRowPosition(0);

    gr_onReqAdmitInfo.setFocusedCell(0, 0);
    gr_carryInOutInfo.setFocusedCell(0, 0);

};



