/**
 * @event 
 * @name gr_carryInOutInfo_oneditend 
 * @description 반출(상차) 예정정보 등록(포털) 셀의 편집이 끝난 경우 발생
 */
scwin.gr_carryInOutInfo_oneditend = async function (rowIndex, columnIndex, value) {

    const gridDlt = $p.getComponentById(gr_carryInOutInfo.getDataList())
    let colId = gr_carryInOutInfo.getColumnID(columnIndex);
    let rowData = gridDlt.getRowJSON(rowIndex);

    if (colId == "crryinoutIntendHh") {
        let tempString = value;
        if (tempString.length < 4 || tempString.substr(0, 2) > 24 || tempString.slice(2, 4) > 60) {
            await $c.win.alert("시간을 올바르게 입력해 주세요 \n      Ex>1245");
            ds_carryInOutInfo.setCellData(rowIndex, "crryinoutIntendHh", "");
        };
    };


    if (colId == "vehclNo") {
        let tempString = value;

        if (tempString.length != 9 && tempString.length != 7) {
            await $c.win.alert("차량번호는 영업번호 9자리를 모두 입력해 주세요 \n      Ex>부산99바1234");
            ds_carryInOutInfo.setCellData(rowIndex, "vehclNo", "");
        } else {

            if (tempString.length == 9) {
                //가운데 숫자체크
                if (Number(tempString.slice(2, 4)) >= 00 &&
                    Number(tempString.slice(2, 4)) <= 99 &&
                    tempString.slice(2, 4).length == 2) {
                } else {
                    await $c.win.alert("세번째 네번째는 숫자이어야 합니다. ");
                    ds_carryInOutInfo.setCellData(rowIndex, "vehclNo", "");
                    return false;
                };

                //마지막 네자리 숫자 체트
                if (Number(tempString.slice(5, 10)) >= 0000 &&
                    Number(tempString.slice(5, 10)) <= 9999 &&
                    tempString.slice(5, 10).length == 4) {
                } else {
                    await $c.win.alert("끝에 네자리는 숫자이어야 합니다. ");
                    ds_carryInOutInfo.setCellData(rowIndex, "vehclNo", "");
                    return false;
                };

                //처음2자리 문자자체크
                let kk = tempString.slice(0, 2);

                if (kk == null) return false;

                for (let i = 0; i < kk.length; i++) {
                    let c = kk.charCodeAt(i);
                    if (!((0xAC00 <= c && c <= 0xD7A3) || (0x3131 <= c && c <= 0x318E))) {
                        await $c.win.alert("처음2자리 한글이어야 합니다.!!! ");
                        ds_carryInOutInfo.setCellData(rowIndex, "vehclNo", "");
                        return false;
                    };
                };

                //가운데1자리 문자자체크
                let kkk = tempString.slice(4, 5);

                if (kkk == null) return false;

                for (let i = 0; i < kkk.length; i++) {
                    let c = kkk.charCodeAt(i);
                    if (!((0xAC00 <= c && c <= 0xD7A3) || (0x3131 <= c && c <= 0x318E))) {
                        await $c.win.alert("다섯번째는 한글이어야 합니다.!!! ");
                        ds_carryInOutInfo.setCellData(rowIndex, "vehclNo", "");
                        return false;
                    };
                };
            };

        };
    };


    if (colId == "vehclIdCardNo") {
        let tempString = value;
        if (tempString.length != 8) {
            await $c.win.alert("ID카드번호는 8자리를 모두 입력해 주세요. \n정확히 입력을 안하시면 EDI 전송시 Error가 발생합니다. \n     Ex>ABCD1234");
            ds_carryInOutInfo.setCellData(rowIndex, "vehclIdCardNo", "");
        };
    };


    if (colId == "drvNm") {
        let tempString = value;

        if (tempString.length < 2) {
            await $c.win.alert("기사명을 올바르게 입력해 주세요 \n      Ex> 김길동");
            ds_carryInOutInfo.setCellData(rowIndex, "drvNm", "");
        };

        if (tempString.length > 0) {
            for (let i = 0; i <= tempString.length; i++) {
                let tempChar = "";
                tempChar = tempString.slice(i, i + 1);
                if (tempChar == "." || tempChar == "," || tempChar == "/" || tempChar == "?"
                    || tempChar == "<" || tempChar == ">" || tempChar == "/" || tempChar == "?"
                    || tempChar == ";" || tempChar == ":" || tempChar == "'" || tempChar == '"'
                    || tempChar == "[" || tempChar == "{" || tempChar == "]" || tempChar == "}"
                    || tempChar == "1" || tempChar == "2" || tempChar == "3" || tempChar == "4"
                    || tempChar == "5" || tempChar == "6" || tempChar == "7" || tempChar == "8"
                    || tempChar == "9" || tempChar == "0" || tempChar == "-" || tempChar == "="
                    || tempChar == "|" || tempChar == "+" || tempChar == "_"
                    || tempChar == "`" || tempChar == "~" || tempChar == "!" || tempChar == "@"
                    || tempChar == "#" || tempChar == "$" || tempChar == "%" || tempChar == "^"
                    || tempChar == "&" || tempChar == "*" || tempChar == "(" || tempChar == ")"
                    || tempChar == "*" || tempChar == "-" || tempChar == "/" || tempChar == ".") {

                    await $c.win.alert("기사명을 올바르게 입력해 주세요 \n      Ex> 김길동");
                    ds_carryInOutInfo.setCellData(rowIndex, "drvNm", "");
                    return false;
                }//if
            }//for
        }//if
    };


    if (colId == "drvTelNo") {
        let tempString = value;

        if (tempString.length < 7) {
            await $c.win.alert("전화번호를 올바르게 입력해 주세요. ");
            ds_carryInOutInfo.setCellData(rowIndex, "drvTelNo", "");
        };

        if (tempString.length > 0) {
            for (let i = 0; i <= tempString.length; i++) {
                let tempChar = "";
                tempChar = tempString.slice(i, i + 1);
                if (tempChar == "." || tempChar == "," || tempChar == "?"
                    || tempChar == "<" || tempChar == ">" || tempChar == "?"
                    || tempChar == ";" || tempChar == ":" || tempChar == "'" || tempChar == '"'
                    || tempChar == "[" || tempChar == "{" || tempChar == "]" || tempChar == "}"
                    || tempChar == "="
                    || tempChar == "|" || tempChar == "+" || tempChar == "_"
                    || tempChar == "`" || tempChar == "~" || tempChar == "!" || tempChar == "@"
                    || tempChar == "#" || tempChar == "$" || tempChar == "%" || tempChar == "^"
                    || tempChar == "&" || tempChar == "*" || tempChar == "(" || tempChar == ")"
                    || tempChar == "*" || tempChar == ".") {

                    $c.win.alert("전화번호를 올바르게 입력해 주세요. ");
                    ds_carryInOutInfo.setCellData(rowIndex, "drvTelNo", "");
                    return false;
                }//if
            }//for
        }//if

    };

};



/**
 * @event 
 * @name ds_carryInOutInfo_onrowpositionchange 
 * @description 반출(상차) 예정정보 등록(포털) 행의 인덱스가 변경된 경우에 발생
 * @asis for=ds_carryInOutInfo event=onRowPosChanged(Row,Colid)
 */
scwin.ds_carryInOutInfo_onrowpositionchange = function (info) {

    if (ds_onReqInfo.getCellData(0, 'admitClsCd') == 'O') {
        gr_carryInOutInfo.setGridReadOnly(false);
    } else {
        gr_carryInOutInfo.setGridReadOnly(true);
    };


    let rowIndex = info.newRowIndex;
    let rowData = ds_carryInOutInfo.getRowJSON(rowIndex);
    let focusIdx = ds_onReqInfo.getRowPosition() ?? 0;
    let focusData = ds_onReqInfo.getRowJSON(focusIdx);

    switch (rowData.crryinoutPrgsStsNm) {
        case '완료':
            gr_carryInOutInfo.setGridReadOnly(true);
            $c.gus.cfDisableObjects([btn_carryingInOutEDI]);
            break;

        case '대기':
            let strOdrNo = focusData.odrNo;

            if (strOdrNo.slice(1, 3) == "C2") {
                if (["TSL", "EAS", "GBH", "KYW"].includes(focusData.lineCd)) {
                    $c.gus.cfDisableObjects([btn_save]);
                };
            } else {
                $c.gus.cfEnableObjects([btn_save]);
            };

            $c.gus.cfDisableObjects([btn_carryingInOutEDI]);
            gr_carryInOutInfo.setGridReadOnly(false);
            break;

        case '예정':
            if (rowData.crryinEdiFlag1 == '') {
                $c.gus.cfDisableObjects([btn_carryingInOutEDI]);
            } else {
                let strOdrNos = focusData.odrNo;
                // 상차지가 신영감만CY 이거나 DPCTCY 이고 오더가 C4 일 경우  반출예정정보등록 버튼 죽임.
                if (['6C24', '6C09'].includes(rowData.wrkPlCd) &&
                    strOdrNos.slice(1, 3) == "C4") {
                    $c.gus.cfDisableObjects([btn_carryingInOutEDI]);
                } else {
                    //현재시간 세팅
                    scwin.f_getTime();
                    if (!(scwin.currTime > "1700" && focusData.wrkPlCd == "6C01")) {
                        $c.gus.cfEnableObjects([btn_carryingInOutEDI]);
                    };
                };
            };
            break;

        default:
            break;
    };

};



/**
 * @event 
 * @name gr_carryInOutInfo_oncellclick 
 * @description 셀이 클릭된 경우 발생
 */
scwin.gr_carryInOutInfo_oncellclick = function (rowIndex, columnIndex, columnId) {

    if (columnId == 'chk') {
        let check = ds_carryInOutInfo.getCellData(rowIndex, 'chk');
        let rowCnt = ds_carryInOutInfo.getTotalRow();

        for (let i = 0; i < rowCnt; i++) {
            ds_carryInOutInfo.setCellData(i, "chk", 0);
        };

        if (check == 1) {
            ds_carryInOutInfo.setCellData(rowIndex, "chk", 1);
        } else {
            ds_carryInOutInfo.setCellData(rowIndex, "chk", 0);
        };
    };

};



