/**
 * @method 
 * @name gr_onReqAdmitInfo_format 
 * @description gr_onReqAdmitInfo customFormatter
 */
scwin.gr_onReqAdmitInfo_format = function (data, formattedData, rowIndex, colIndex) {

    let colID = this.getColumnID(colIndex);
    let rowData = $p.getComponentById(this.getDataList()).getRowJSON(rowIndex);

    switch (colID) {
        case 'unCreatQty':
            const nAdmitQty = $c.num.parseFloat(rowData['admitQty'], 0);
            const nIntendQty = $c.num.parseFloat(rowData['intendQty'], 0);
            const nCrryoutQty = $c.num.parseFloat(rowData['crryoutQty'], 0);

            return nAdmitQty - (nIntendQty + nCrryoutQty);
    };

};
